import React, { useState, useEffect } from 'react';
import { getAdminBookings } from '../../utils/adminApi';
import './AdminDashboardPage.css';

const statusColor = (status) => {
  const paid = status === 'Paid' || status === 'paid';
  return paid ? '#22c55e' : '#f59e0b';
};

const AdminBookingsPage = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    loadBookings();
  }, []);

  const loadBookings = async () => {
    try {
      const res = await getAdminBookings();
      const data = res.data || [];
      // Sort by most recent first
      data.sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
      setBookings(data);
    } catch { setBookings([]); }
    finally { setLoading(false); }
  };

  const filtered = bookings.filter((b) => {
    if (!search) return true;
    const s = search.toLowerCase();
    return (
      (b.userName || '').toLowerCase().includes(s) ||
      (b.userEmail || '').toLowerCase().includes(s) ||
      (b.slot || '').toLowerCase().includes(s) ||
      String(b.id || '').includes(s)
    );
  });

  return (
    <div className="admin-dashboard-theme">
      <div className="dashboard-welcome">
        <div className="welcome-content">
          <h1>Bookings</h1>
          <p>All parking bookings — most recent first ({bookings.length} total)</p>
        </div>
        <div className="welcome-icon">📋</div>
      </div>

      {/* Search */}
      <div className="mb-4">
        <input type="text" className="form-control" placeholder="Search by user, email, slot, or booking ID..."
          value={search} onChange={(e) => setSearch(e.target.value)} />
      </div>

      {/* Booking Detail Modal */}
      {selected && (
        <div className="chart-panel mb-4">
          <div className="d-flex justify-content-between mb-3">
            <h6 className="fw-bold">Booking #{selected.id} Details</h6>
            <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelected(null)}>
              <i className="bi bi-x"></i> Close
            </button>
          </div>
          <div className="row g-3">
            <div className="col-md-6">
              <small className="text-muted d-block">User</small>
              <strong>{selected.userName || 'N/A'}</strong>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Email</small>
              <strong>{selected.userEmail || 'N/A'}</strong>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Slot</small>
              <strong>{selected.slot || 'N/A'}</strong>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Duration</small>
              <strong>{selected.duration}h</strong>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Amount</small>
              <strong>₹{selected.amount}</strong>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Status</small>
              <span className="badge" style={{ backgroundColor: selected.paid ? '#22c55e' : '#f59e0b', color: '#fff' }}>
                {selected.paid ? 'Paid' : 'Pending'}
              </span>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Payment Method</small>
              <strong>{selected.paymentMethod || 'N/A'}</strong>
            </div>
            <div className="col-md-6">
              <small className="text-muted d-block">Booked At</small>
              <strong>{selected.createdAt ? new Date(selected.createdAt).toLocaleString() : 'N/A'}</strong>
            </div>
            {selected.validUntil && (
              <div className="col-md-6">
                <small className="text-muted d-block">Valid Until</small>
                <strong>{new Date(selected.validUntil).toLocaleString()}</strong>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Table */}
      {loading ? (
        <div className="text-center py-5"><div className="spinner-border text-primary"></div></div>
      ) : (
        <div className="chart-panel">
          <div className="table-responsive">
            <table className="table table-hover mb-0">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>User</th>
                  <th>Email</th>
                  <th>Slot</th>
                  <th>Duration</th>
                  <th>Amount</th>
                  <th>Status</th>
                  <th>Booked At</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr><td colSpan="9" className="text-center text-muted py-4">No bookings found</td></tr>
                ) : filtered.map((b) => (
                  <tr key={b.id}>
                    <td>#{b.id}</td>
                    <td className="fw-bold">{b.userName || 'N/A'}</td>
                    <td><small>{b.userEmail || 'N/A'}</small></td>
                    <td>{b.slot}</td>
                    <td>{b.duration}h</td>
                    <td>₹{b.amount}</td>
                    <td>
                      <span className="badge" style={{ backgroundColor: b.paid ? '#22c55e' : '#f59e0b', color: '#fff' }}>
                        {b.paid ? 'Paid' : 'Pending'}
                      </span>
                    </td>
                    <td><small>{b.createdAt ? new Date(b.createdAt).toLocaleDateString() : ''}</small></td>
                    <td>
                      <button className="btn btn-sm btn-outline-primary" onClick={() => setSelected(b)}>
                        <i className="bi bi-eye"></i>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminBookingsPage;
